    "content-canon-mn28": {
        "type": "content",
        "title": "MN 28: The Longer Simile of the Elephantãs Footprint",
        "description": "",
        "tags": "mn time thought elements origination",
        "category": "canon",
        "boost": 2,
        "authors": [],
        "translator": "Bhante Sujato",
        "content": " When a space is enclosed by sticks, creepers, grass, and mud it becomes known as a ãbuildingã. In the same way, when a space is enclosed by bones, sinews, flesh, and skin it becomes known as a ãformã. The Venerable Sáriputta shows how all of the teachings fit inside the Four Noble Truths. ",
        "url": "/content/canon/mn28"
    },
  
    
    
    "content-canon-mn29": {
        "type": "content",
        "title": "MN 29: The Greater Discourse on the Simile of the Heartwood",
        "description": "",
        "tags": "mn imagery nibbana function",
        "category": "canon",
        "boost": 4,
        "authors": [],
        "translator": "Bhikkhu Bodhi",
        "content": " So this holy life, bhikkhus, does not have gain, honour, and renown for its benefit, or the attainment of virtue for its benefit, or the attainment of concentration for its benefit, or knowledge and vision for its benefit. But it is this unshakeable deliverance of mind that is the goal of this holy life, its heartwood, and its end. ",
        "url": "/content/canon/mn29"
    },
  
    
    
